/* ========================================================= HOMEPAGE HERO VIDEO ========================================================= */
/* Keep the existing image as a fallback while the video loads */ .home-hero { position: relative; overflow: hidden; }
/* Full-size background video */ .hero-video { position: absolute; inset: 0; z-index: 0;
width: 100%; height: 100%;
object-fit: cover; object-position: center center;
pointer-events: none; }
/* Keep the dark overlay above the video */ .home-hero-overlay { position: absolute; inset: 0; z-index: 1; }
/* Keep the headline, paragraph, and buttons above everything */ .home-hero-content { position: relative; z-index: 2; }
/* Smaller, more balanced headline */ .home-hero-content h1 { max-width: 760px; font-size: clamp(40px, 3.8vw, 58px); line-height: 1.08; font-weight: 600; text-shadow: 0 2px 10px rgba(0, 0, 0, 0.35); }
/* Refined supporting paragraph */ .home-hero-content p { max-width: 650px; color: rgba(255, 255, 255, 0.94); font-size: 20px; line-height: 1.6; text-shadow: 0 2px 8px rgba(0, 0, 0, 0.3); }
/* Mobile adjustments */ @media (max-width: 600px) { .home-hero-content h1 { font-size: 38px; line-height: 1.08; }
.home-hero-content p { font-size: 16px; line-height: 1.55; }
.hero-video { object-position: center center; } }
